import math


def round_half_even(x):
    floor_val = math.floor(x)
    diff = x - floor_val

    if diff < 0.5:
        return int(floor_val)
    elif diff > 0.5:
        return int(floor_val) + 1
    else:
        if floor_val % 2 == 0:
            return int(floor_val)
        else:
            return int(floor_val) + 1

